<!-- eslint-disable vue/max-len -->
<template>
<svg
	:aria-label
	class="inverse-pendulum-skateboard"
	role="img"
	:viewBox
>
	<defs>
		<marker
			id="arrow-head"
			markerHeight="8"
			markerWidth="8"
			orient="auto"
			refX="3"
			refY="3"
		>
			<path d="M0,0 L6,3 L0,6 Z" fill="currentColor" />
		</marker>
		<marker
			id="force-arrow-head"
			markerHeight="8"
			markerWidth="8"
			orient="auto"
			refX="3"
			refY="3"
		>
			<path class="force-arrow-head" d="M0,0 L6,3 L0,6 Z" />
		</marker>
		<marker
			id="force-arrow-head-limited"
			markerHeight="8"
			markerWidth="8"
			orient="auto"
			refX="3"
			refY="3"
		>
			<path class="force-arrow-head-limited" d="M0,0 L6,3 L0,6 Z" />
		</marker>

		<filter id="soft-shadow"
			height="140%"
			width="140%"
			x="-20%"
			y="-20%"
		>
			<feDropShadow dx="0"
				dy="3"
				flood-opacity="0.22"
				stdDeviation="3"
			/>
		</filter>
	</defs>

	<!-- Background -->
	<rect class="bg"
		:height="viewBoxHeight"
		rx="18"
		:width="viewBoxWidth"
		:x="viewBoxX"
		:y="viewBoxY"
	/>

	<!-- Ground / coordinate axis -->
	<line
		class="ground-line"
		:x1="padding"
		:x2="width - padding"
		:y1="groundY"
		:y2="groundY"
	/>
	<line
		class="axis-line"
		:x1="originX"
		:x2="originX"
		:y1="groundY + 24"
		:y2="padding"
	/>
	<text class="axis-label" :x="width - padding - 10" :y="groundY + 22">x</text>
	<text class="axis-label" :x="originX + 8" :y="padding + 12">y</text>

	<!-- Cart position indicator -->
	<g v-if="showPositionGuide" class="position-guide">
		<line :x1="originX"
			:x2="cartCx"
			:y1="groundY + 12"
			:y2="groundY + 12"
		/>
		<text text-anchor="middle" :x="(originX + cartCx) / 2" :y="groundY + 34">
			x = {{ format(positionX) }} m
		</text>
	</g>

	<!-- Skateboard / cart -->
	<g filter="url(#soft-shadow)" :transform="`translate(${cartCx}, ${cartY})`">
		<!-- deck -->
		<path
			class="deck"
			:d="deckPath"
		/>

		<!-- grip tape -->
		<path
			class="grip"
			:d="gripPath"
		/>

		<!-- trucks -->
		<g class="truck">
			<line :x1="-wheelBase / 2"
				:x2="-wheelBase / 2"
				y1="15"
				y2="29"
			/>
			<line :x1="wheelBase / 2"
				:x2="wheelBase / 2"
				y1="15"
				y2="29"
			/>
		</g>

		<!-- wheels -->
		<circle class="wheel"
			:cx="-wheelBase / 2"
			cy="35"
			:r="wheelRadius"
		/>
		<circle class="wheel"
			:cx="wheelBase / 2"
			cy="35"
			:r="wheelRadius"
		/>

		<!-- pivot -->
		<circle class="pivot"
			cx="0"
			:cy="-deckHeight / 2"
			r="7"
		/>
	</g>

	<!-- Pendulum body: bottom center slightly below pivot, rotating around pivot. -->
	<g class="pendulum-image-layer" :transform="pendulumImageTransform">
		<g class="pendulum-figure"
			:class="{ 'is-dark': isDarkTheme }"
			:transform="pendulumFigureTransform"
		>
		
